export function fftBigintMultiplyDigitArrays(a: number[], b: number[]): number[] {
    if (a.length === 0 || b.length === 0) return [0];

    let n = 1;
    while (n < a.length + b.length - 1) n <<= 1;

    const faRe = new Float64Array(n);
    const faIm = new Float64Array(n);
    const fbRe = new Float64Array(n);
    const fbIm = new Float64Array(n);

    for (let i = 0; i < a.length; i++) faRe[a.length - 1 - i] = a[i];
    for (let i = 0; i < b.length; i++) fbRe[b.length - 1 - i] = b[i];

    function fft(re: Float64Array, im: Float64Array, invert: boolean) {
        const n = re.length;
        let j = 0;
        for (let i = 1; i < n; i++) {
            const bit = n >> 1;
            for (; j & bit; bit >>= 1) j ^= bit;
            j ^= bit;
            if (i < j) {
                let t;
                t = re[i]; re[i] = re[j]; re[j] = t;
                t = im[i]; im[i] = im[j]; im[j] = t;
            }
        }

        for (let len = 2; len <= n; len <<= 1) {
            const halfLen = len >> 1;
            const angle = (invert ? -1 : 1) * 2 * Math.PI / len;
            const wRe = Math.cos(angle);
            const wIm = Math.sin(angle);

            for (let i = 0; i < n; i += len) {
                let curRe = 1, curIm = 0;
                for (let k = 0; k < halfLen; k++) {
                    const uRe = re[i + k];
                    const uIm = im[i + k];
                    const vRe = re[i + k + halfLen] * curRe - im[i + k + halfLen] * curIm;
                    const vIm = re[i + k + halfLen] * curIm + im[i + k + halfLen] * curRe;

                    re[i + k] = uRe + vRe;
                    im[i + k] = uIm + vIm;
                    re[i + k + halfLen] = uRe - vRe;
                    im[i + k + halfLen] = uIm - vIm;

                    const nextCurRe = curRe * wRe - curIm * wIm;
                    const nextCurIm = curRe * wIm + curIm * wRe;
                    curRe = nextCurRe;
                    curIm = nextCurIm;
                }
            }
        }

        if (invert) {
            for (let i = 0; i < n; i++) {
                re[i] /= n;
                im[i] /= n;
            }
        }
    }

    fft(faRe, faIm, false);
    fft(fbRe, fbIm, false);

    const cr = new Float64Array(n);
    const ci = new Float64Array(n);
    for (let i = 0; i < n; i++) {
        cr[i] = faRe[i] * fbRe[i] - faIm[i] * fbIm[i];
        ci[i] = faRe[i] * fbIm[i] + faIm[i] * fbRe[i];
    }

    fft(cr, ci, true);

    const res: number[] = [];
    let carry = 0;
    for (let i = 0; i < n; i++) {
        const val = Math.round(cr[i]) + carry;
        carry = Math.floor(val / 10);
        res.push(val % 10);
    }
    while (carry > 0) {
        res.push(carry % 10);
        carry = Math.floor(carry / 10);
    }

    while (res.length > 1 && res[res.length - 1] === 0) {
        res.pop();
    }

    return res.reverse();
}

