function fft(aRe: number[], aIm: number[], invert: boolean) {
    const n = aRe.length;
    // Bit reversal
    let j = 0;
    for (let i = 1; i < n; i++) {
        const bit = n >> 1;
        for (j ^= bit; j & bit; bit >>= 1) j ^= bit;
        if (i < j) {
            let temp;
            temp = aRe[i]; aRe[i] = aRe[j]; aRe[j] = temp;
            temp = aIm[i]; aIm[i] = aIm[j]; aIm[j] = temp;
