    // Cooley-Tukey
    for (let len = 2; len <= n; len <<= 1) {
        const halfLen = len >> 1;
        const angle = (invert ? -1 : 1) * 2 * Math.PI / len;
        const wRe = Math.cos(angle);
        const wIm = Math.sin(angle);
        for (let i = 0; i < n; i += len) {
            let curRe = 1, curIm = 0;
            for (let j = 0; j < halfLen; j++) {
                const uRe = aRe[i + j];
                const uIm = aIm[i + j];
                const vRe = aRe[i + j + halfLen] * curRe - aIm[i + j + halfLen] * curIm;
                const vIm = aRe[i + j + halfLen] * curIm + aIm[i + j + halfLen] * curRe;
