export function lruCache(capacity: number, operations: readonly (readonly ['get' | 'put', number, number?])[]): (number | null)[] {
    const cache = new Map<number, number>();
    const results: (number | null)[] = [];

    for (const op of operations) {
        if (op[0] === 'get') {
            const key = op[1];
            if (cache.has(key)) {
                const val = cache.get(key)!;
                cache.delete(key);
                cache.set(key, val);
                results.push(val);
            } else {
                results.push(null);
            }
        } else {
            const key = op[1];
            const val = op[2]!;
            if (cache.has(key)) {
                cache.delete(key);
            } else if (cache.size === capacity && capacity > 0) {
                const lruKey = cache.keys().next().value!;
                cache.delete(lruKey);
            }
            cache.set(key, val);
            results.push(null);
        }
    }

    return results;
}

