export function mergeSortLinkedList(head: {value: number; next: any} | null): {value: number; next: any} | null {
    if (!head || !head.next) return head;

    let slow = head;
    let fast = head.next;
    while (fast && fast.next) {
        slow = slow.next!;
        fast = fast.next.next!;
    }
    const rightHead = slow.next;
    slow.next = null;

    const leftSorted = mergeSortLinkedList(head);
    const rightSorted = mergeSortLinkedList(rightHead!);

    const dummy: {value: number; next: any} = { value: 0, next: null };
    let curr = dummy;
    let l = leftSorted;
    let r = rightSorted;

    while (l && r) {
        if (l.value <= r.value) {
            curr.next = l;
            l = l.next!;
        } else {
            curr.next = r;
            r = r.next!;
        }
        curr = curr.next!;
    }
    curr.next = l || r;

    return dummy.next;
}

