export function minStack(operations: readonly (readonly ['push' | 'pop' | 'top' | 'getMin', number?])[]): (number | null)[] {
    const stack: number[] = [];
    const mins: number[] = [];
    const res: (number | null)[] = [];

    for (const [op, val] of operations) {
        switch (op) {
            case 'push':
                if (val !== undefined) {
                    stack.push(val);
                    if (mins.length === 0 || val <= mins[mins.length - 1]) {
                        mins.push(val);
                    }
                }
                break;
            case 'pop':
                const popped = stack.pop();
                if (popped !== undefined && mins.length > 0 && popped === mins[mins.length - 1]) {
                    mins.pop();
                }
                break;
            case 'top':
                res.push(stack.length > 0 ? stack[stack.length - 1] : null);
                break;
            case 'getMin':
                res.push(mins.length > 0 ? mins[mins.length - 1] : null);
                break;
        }
    }

    return res;
}

