export function toyRsaBigint(p: bigint, q: bigint, e: bigint, message: bigint): {publicKey: {n: bigint; e: bigint}; privateKey: {n: bigint; d: bigint}; cipher: bigint; decrypted: bigint} {
    const n = p * q;
    const phi = (p - 1n) * (q - 1n);

    function modPow(base: bigint, exp: bigint, mod: bigint): bigint {
        let res = 1n;
        base %= mod;
        while (exp > 0n) {
            if (exp % 2n === 1n) {
                res = (res * base) % mod;
            }
            exp /= 2n;
            base = (base * base) % mod;
        }
        return res;
    }

    function modInverse(a: bigint, m: bigint): bigint {
        let m0 = m;
        let y = 0n;
        let x = 1n;
        if (m === 1n) return 0n;
        while (a > 1n) {
            const q = a / m;
            const t = m;
            m = a % m;
            a = t;
            const ty = y;
            y = x - q * y;
            x = ty;
        }
        return (x % m0 + m0) % m0;
    }

    const d = modInverse(e, phi);
    const cipher = modPow(message, e, n);
    const decrypted = modPow(cipher, d, n);

    return {
        publicKey: { n, e },
        privateKey: { n, d },
        cipher,
        decrypted
    };
}

