        return res;
    }

    function modInverse(a: bigint, m: bigint): bigint {
        let m0 = m;
        let y = 0n;
        let x = 1n;
        if (m === 1n) return 0n;
        while (a > 1n) {
            const q = a / m;
            const t = m;
            m = a % m;
            a = t;
            const ty = y;
            y = x - q * y;
