/* Named <details name="..."> grouping limits one open panel, but browser support may vary by engine/version. */
.accordion {
	display: grid;
	gap: 0.75rem;
}

.accordion details {
	border: 1px solid #d3d9e4;
	border-radius: 0.5rem;
	background: #ffffff;
	overflow: clip;
}

.accordion summary {
	list-style: none;
	cursor: pointer;
	padding: 0.9rem 1rem;
	font-weight: 600;
	display: flex;
	align-items: center;
	justify-content: space-between;
}

.accordion summary::-webkit-details-marker {
	display: none;
}

.accordion summary::after {
	content: 'v';
	transition: transform 180ms ease;
}

.accordion details[open] > summary::after {
	transform: rotate(180deg);
}

.accordion__content {
	display: grid;
	grid-template-rows: 0fr;
	transition: grid-template-rows 220ms ease;
}

.accordion__content > div {
	overflow: hidden;
	padding-inline: 1rem;
	padding-bottom: 0;
}

.accordion details[open] .accordion__content {
	grid-template-rows: 1fr;
}

.accordion details[open] .accordion__content > div {
	padding-bottom: 1rem;
}

