export function avlTreeInsertRebalance(values: number[]): {value: number; height: number; left: any; right: any} | null {
    type Node = { value: number; height: number; left: any; right: any };

    const getHeight = (n: Node | null): number => n?.height ?? 0;
    const getBalance = (n: Node | null): number => (n ? getHeight(n.left) - getHeight(n.right) : 0);

    const updateHeight = (n: Node): void => {
        n.height = 1 + Math.max(getHeight(n.left), getHeight(n.right));
    };

    const rightRotate = (y: Node): Node => {
        const x = y.left!;
        const T2 = x.right;
        x.right = y;
        y.left = T2;
        updateHeight(y);
        updateHeight(x);
        return x;
    };

    const leftRotate = (x: Node): Node => {
        const y = x.right!;
        const T2 = y.left;
        y.left = x;
        x.right = T2;
        updateHeight(x);
        updateHeight(y);
        return y;
    };

    const insert = (node: Node | null, val: number): Node => {
        if (!node) return { value: val, height: 1, left: null, right: null };

        if (val < node.value) {
            node.left = insert(node.left, val);
        } else if (val > node.value) {
            node.right = insert(node.right, val);
        } else {
            return node;
        }

        updateHeight(node);
        const balance = getBalance(node);

        // Left Left
        if (balance > 1 && val < (node.left! as Node).value) {
            return rightRotate(node);
        }
        // Right Right
        if (balance < -1 && val > (node.right! as Node).value) {
            return leftRotate(node);
        }
        // Left Right
        if (balance > 1 && val > (node.left! as Node).value) {
            node.left = leftRotate(node.left! as Node);
            return rightRotate(node);
        }
        // Right Left
        if (balance < -1 && val < (node.right! as Node).value) {
            node.right = rightRotate(node.right! as Node);
            return leftRotate(node);
        }

        return node;
    };

    let root: Node | null = null;
    for (const v of values) {
        root = insert(root, v);
    }
    return root;
}

