				value: unknown;
				height: unknown;
				left: unknown;
				right: unknown;
			};
			return (
				typeof nodeValue === 'number' &&
				typeof nodeHeight === 'number' &&
				(left === null || typeof left === 'object') &&
				(right === null || typeof right === 'object')
			);
		};

		const build = (values: number[]): AvlNode | null => {
