    while (i < node.keys.length && key > node.keys[i]) i++;

    if (i < node.keys.length && node.keys[i] === key) {
      if (node.children.length === 0) {
        node.keys.splice(i, 1);
        return;
      } else {
        const left = node.children[i];
        const right = node.children[i + 1];

        if (left.keys.length >= t) {
          let pred = left;
          while (pred.children.length > 0) pred = pred.children[pred.children.length - 1];
          const predKey = pred.keys[pred.keys.length - 1];
          node.keys[i] = predKey;
          deleteKey(left, predKey);
        } else if (right.keys.length >= t) {
          let succ = right;
          while (succ.children.length > 0) succ = succ.children[0];
          const succKey = succ.keys[0];
          node.keys[i] = succKey;
          deleteKey(right, succKey);
        } else {
          left.keys.push(key);
          left.keys.push(...right.keys);
          if (left.children.length > 0) {
            left.children.push(...right.children);
          }
          node.keys.splice(i, 1);
          node.children.splice(i, 1);
          deleteKey(left, key);
        }
      }
    } else {
      if (node.children.length === 0) return;

      let ci = i;
      const child = node.children[ci];

      if (child.keys.length < t) {
        if (ci > 0 && node.children[ci - 1].keys.length >= t) {
          borrowFromLeft(node, ci);
        } else if (ci < node.children.length - 1 && node.children[ci + 1].keys.length >= t) {
          borrowFromRight(node, ci);
        } else {
          mergeNodes(node, ci);
          child = node.children[ci];
        }
      }

      deleteKey(child, key);
    }
  }

  function delete(key: number): void {
    if (!root) return;
    if (!search(key)) return;
    deleteKey(root, key);
    if (root.keys.length === 0 && root.children.length > 0) {
      root = root.children[0];
    }
  }

  function keys(): number[] {
    const result: number[] = [];
    function traverse(node: Node | null) {
      if (!node) return;
      for (let i = 0; i < node.keys.length; i++) {
        if (node.children.length > 0) traverse(node.children[i]);
        result.push(node.keys[i]);
      }
      if (node.children.length > 0) traverse(node.children[node.children.length - 1]);
    }
    traverse(root);
    return result;
  }

  return { insert, search, delete: delete, keys };
}

