export function bloomFilterNHashFunctions(size: number, hashCount: number, wordsToAdd: string[], queries: string[]): boolean[] {
    const bits = new Array(size).fill(false);

    for (const word of wordsToAdd) {
        let h1 = 0;
        let h2 = 1;
        for (let i = 0; i < word.length; i++) {
            const c = word.charCodeAt(i);
            h1 = ((h1 << 5) - h1 + c) | 0;
            h2 = ((h2 << 5) - h2 + c) | 0;
        }
        h1 >>>= 0;
        h2 >>>= 0;

        for (let i = 0; i < hashCount; i++) {
            bits[(h1 + i * h2) % size] = true;
        }
    }

    const results: boolean[] = [];
    for (const word of queries) {
        let h1 = 0;
        let h2 = 1;
        for (let i = 0; i < word.length; i++) {
            const c = word.charCodeAt(i);
            h1 = ((h1 << 5) - h1 + c) | 0;
            h2 = ((h2 << 5) - h2 + c) | 0;
        }
        h1 >>>= 0;
        h2 >>>= 0;

        let allSet = true;
        for (let i = 0; i < hashCount; i++) {
            if (!bits[(h1 + i * h2) % size]) {
                allSet = false;
                break;
            }
        }
        results.push(allSet);
    }

    return results;
}

