export function trieAutocomplete(words: string[], prefixes: string[]): string[][] {
  interface TrieNode {
    children: Record<string, TrieNode>;
    word?: string;
  }

  const root: TrieNode = { children: {} };

  for (const w of words) {
    let node = root;
    for (const ch of w) {
      if (!node.children[ch]) {
        node.children[ch] = { children: {} };
      }
      node = node.children[ch];
    }
    node.word = w;
  }

  const collect = (node: TrieNode, res: string[]) => {
    if (node.word !== undefined) {
      res.push(node.word);
    }
    for (const k of Object.keys(node.children)) {
      collect(node.children[k], res);
    }
  };

  const result: string[][] = [];
  for (const prefix of prefixes) {
    let node = root;
    let found = true;
    for (const ch of prefix) {
      if (!node.children[ch]) {
        found = false;
        break;
      }
      node = node.children[ch];
    }

    if (found) {
      const completions: string[] = [];
      collect(node, completions);
      completions.sort();
      result.push(completions);
    } else {
      result.push([]);
    }
  }

  return result;
}

