export function getISOWeek(date: Date): {week: number; year: number} {
    const tmpDate = new Date(Date.UTC(date.getFullYear(), date.getMonth(), date.getDate()));
    const dayNum = tmpDate.getUTCDay() === 0 ? 7 : tmpDate.getUTCDay();
