export function dateInputToIso(input: string): string | null {
  if (!/^\d{4}-\d{2}-\d{2}$/.test(input)) return null;
  const [y, m, d] = input.split('-').map(Number);
  if (m < 1 || m > 12 || d < 1) return null;
