export type Row = Record<string, string | number | boolean | null>;

export function jsonToCsv(rows: Row[]): string {
  if (!Array.isArray(rows)) throw new Error('Invalid input: expected array');
  for (const row of rows) {
    if (row === null || typeof row !== 'object') throw new Error('Invalid input: expected object in array');
  }

  const escape = (val: string | number | boolean | null): string => {
    const str = String(val ?? '');
    if (/[,"\n\r]/.test(str)) return `"${str.replace(/"/g, '""')}"`;
    return str;
  };

  if (rows.length === 0) return '';

  const headers = Array.from(new Set(rows.flatMap(Object.keys)));
  const lines = [headers.join(',')];
  for (const row of rows) {
    lines.push(headers.map(h => escape(row[h])).join(','));
  }
  return lines.join('\n');
}

export function csvToJson(csv: string): Row[] {
  if (typeof csv !== 'string') throw new Error('Invalid input: expected string');

  const rows: string[][] = [];
  let i = 0;
  const len = csv.length;

  const parseField = (): string => {
    let field = '';
    if (i < len && csv[i] === '"') {
      i++;
      while (i < len) {
        if (csv[i] === '"') {
          if (i + 1 < len && csv[i+1] === '"') {
            field += '"';
            i += 2;
          } else {
            i++;
            break;
          }
        } else {
          field += csv[i];
          i++;
        }
      }
    } else {
      while (i < len && csv[i] !== ',' && csv[i] !== '\n' && csv[i] !== '\r') {
        field += csv[i];
        i++;
      }
    }
    return field;
  };

  const parseLine = (): string[] => {
    const line: string[] = [];
    while (i < len) {
      line.push(parseField());
      if (i < len && csv[i] === ',') i++;
      else break;
    }
    if (i < len && (csv[i] === '\n' || csv[i] === '\r')) {
      if (csv[i] === '\r' && i + 1 < len && csv[i+1] === '\n') i++;
      i++;
    }
    return line;
  };

  while (i < len) {
    const line = parseLine();
    rows.push(line);
  }

  if (rows.length === 0) return [];
  const headers = rows[0];
  const result: Row[] = [];
  for (let r = 1; r < rows.length; r++) {
    const row: Row = {};
    for (let c = 0; c < headers.length; c++) {
      let val = rows[r][c] ?? '';
      if (val === 'true') val = true as any;
      else if (val === 'false') val = false as any;
      else if (val === 'null') val = null;
      else {
        const num = Number(val);
        if (!isNaN(num) && val.trim() !== '') val = num;
      }
      row[headers[c]] = val as any;
    }
    result.push(row);
  }
  return result;
}

export function jsonToXml(rows: Row[], rootElement: string, rowElement: string): string {
  if (!Array.isArray(rows)) throw new Error('Invalid input: expected array');
  for (const row of rows) {
    if (row === null || typeof row !== 'object') throw new Error('Invalid input: expected object in array');
  }

  const escapeXml = (str: string): string => 
    str.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;').replace(/'/g, '&apos;');

  let xml = `<${rootElement}>`;
  for (const row of rows) {
    xml += `<${rowElement}>`;
    for (const [key, value] of Object.entries(row)) {
      if (value === null || value === undefined) continue;
      const valStr = String(value);
      xml += `<${escapeXml(key)}>${escapeXml(valStr)}</${escapeXml(key)}>`;
    }
    xml += `</${rowElement}>`;
  }
  xml += `</${rootElement}>`;
  return xml;
}

export function xmlToJson(xml: string, rowElement: string): Row[] {
  if (typeof xml !== 'string') throw new Error('Invalid input: expected string');

  const unescapeXml = (str: string): string => 
    str.replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&quot;/g, '"').replace(/&apos;/g, "'");

  const rows: Row[] = [];
  const rowElementEscaped = rowElement.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  const rowRegex = new RegExp(`<${rowElementEscaped}>([\\s\\S]*?)</${rowElementEscaped}>`, 'g');
  let match;

  while ((match = rowRegex.exec(xml)) !== null) {
    const rowContent = match[1];
    const row: Row = {};
    const childRegex = /<([a-zA-Z_:][\w.-]*)>([\s\S]*?)<\/\1>/g;
    let childMatch;
    while ((childMatch = childRegex.exec(rowContent)) !== null) {
      row[childMatch[1]] = unescapeXml(childMatch[2]);
    }
    rows.push(row);
  }

  return rows;
}

export function csvToXml(csv: string, rootElement: string, rowElement: string): string {
  if (typeof csv !== 'string') throw new Error('Invalid input: expected string');
  const rows = csvToJson(csv);
  return jsonToXml(rows, rootElement, rowElement);
}

export function xmlToCsv(xml: string, rowElement: string): string {
  if (typeof xml !== 'string') throw new Error('Invalid input: expected string');
  const rows = xmlToJson(xml, rowElement);
  return jsonToCsv(rows);
}

