export function parseIntStrict(input: string): number | null {
    if (input === '') return null;

    const trimmed = input.trim();
    if (trimmed === '') return null;

    // Check for valid integer format: optional minus, then digits
    // Must be a strict integer - no decimals, no scientific notation, no extra characters
    const regex = /^-?\d+$/;
    if (!regex.test(trimmed)) return null;

    const num = Number(trimmed);

    // Check for overflow (though JS numbers are safe up to 2^53)
    if (!Number.isInteger(num)) return null;

    return num;
}

export function parseIntStrict(input: string): number | null {
    if (input === '') return null;

    const trimmed = input.trim();
    if (trimmed === '') return null;

    // Check for valid integer format: optional minus, then digits
    // Must be a strict integer - no decimals, no scientific notation, no extra characters
    const regex = /^-?\d+$/;
    if (!regex.test(trimmed)) return null;

    const num = Number(trimmed);

    // Check for overflow (though JS numbers are safe up to 2^53)
    if (!Number.isInteger(num)) return null;

    return num;
}

