        if (c !== 32 && c !== 9 && c !== 10 && c !== 13) break;
        i++;
    }

    if (i === len) return null;

    let j = len - 1;
    while (j >= 0 && s.charCodeAt(j) <= 32) {
        j--;
    }

    let num = 0;
    let isNegative = false;
    let hasDecimal = false;
    let decimalPlaces = 0;
    let hasDigit = false;

    if (i <= j && s.charCodeAt(i) === 45) {
        isNegative = true;
        i++;
    }

    while (i <= j) {
        const code = s.charCodeAt(i);
        if (code >= 48 && code <= 57) {
