export function fibonacci(n: number): number {
    if (n <= 1) {
        return n;
    }
    const memo: Record<number, number> = {};
    function fibHelper(k: number): number {
        if (k in memo) {
            return memo[k];
        }
        if (k <= 1) {
            return k;
        }
        memo[k] = fibHelper(k - 1) + fibHelper(k - 2);
        return memo[k];
    }
    return fibHelper(n);
}

