import axios from 'axios';

let baseURL = '';
const defaultHeaders: Record<string, string> = {};

export function configure(options: { baseURL: string; headers?: Record<string, string> }): void {
  baseURL = options.baseURL;
  if (options.headers) {
    Object.assign(defaultHeaders, options.headers);
  }
}

export async function get<T>(path: string, params?: Record<string, unknown>): Promise<T> {
  const response = await axios.get<T>(baseURL + path, {
    params,
    headers: defaultHeaders,
  });
  return response.data;
}

export async function post<T>(path: string, body: unknown, options?: { headers?: Record<string, string> }): Promise<T> {
  const response = await axios.post<T>(baseURL + path, body, {
    headers: {
      ...defaultHeaders,
      ...(options?.headers ?? {}),
    },
  });
  return response.data;
}

export function buildQueryString(params: Record<string, unknown>): string {
  return Object.entries(params)
    .filter(([, v]) => v !== undefined && v !== null)
    .map(([k, v]) => `${encodeURIComponent(k)}=${encodeURIComponent(String(v))}`)
    .join('&');
}

interface RawResponseData {
  items?: Array<{ id: string | number; name?: string; title?: string; meta?: Record<string, unknown> }>;
}

interface RawResponse {
  data?: RawResponseData;
}

function isRawResponseWithItems(raw: unknown): raw is RawResponse {
  if (typeof raw !== 'object' || raw === null || !('data' in raw)) return false;
  const data = (raw as RawResponse).data;
  return Array.isArray(data?.items);
}

type ParsedItem = { id: string | number; label: string; meta: Record<string, unknown> };

