export class EventBus {
  private _events: Record<string, Array<{ fn: Function; ctx: any; once: boolean }>> = {};

  /**
   * Registers an event listener for the specified event.
   * @param event - The name of the event to listen to.
   * @param callback - The function to call when the event is emitted.
   * @param context - The context (`this`) to use when calling the callback. Defaults to the EventBus instance.
   * @returns The EventBus instance for chaining.
   */
  on(event: string, callback: Function, context?: any): this {
    const listeners = this._events[event] || (this._events[event] = []);
    listeners.push({ fn: callback, ctx: context || this, once: false });
    return this;
  }

  /**
   * Registers a one-time event listener for the specified event.
   * @param event - The name of the event to listen to.
   * @param callback - The function to call when the event is emitted.
   * @param context - The context (`this`) to use when calling the callback. Defaults to the EventBus instance.
   * @returns The EventBus instance for chaining.
   */
  once(event: string, callback: Function, context?: any): this {
    const self = this;
    const wrapper = (...args: any[]) => {
      self.off(event, wrapper);
      callback.apply(context || self, args);
    };
    (wrapper as any)._fn = callback;
    return this.on(event, wrapper, context);
  }

  /**
   * Emits the specified event, passing along any provided arguments to listeners.
   * @param event - The name of the event to emit.
   * @param args - Arguments to pass to the event listeners.
   * @returns The EventBus instance for chaining.
   */
  emit(event: string, ...args: any[]): this {
    const listeners = this._events[event];
    if (!listeners) return this;

    const listenersCopy = listeners.slice();
    for (let i = 0; i < listenersCopy.length; i++) {
      listenersCopy[i].fn.apply(listenersCopy[i].ctx, args);
    }
    return this;
  }

  /**
   * Removes an event listener for the specified event.
   * @param event - The name of the event to remove listeners from.
   * @param callback - The specific callback function to remove. If omitted, all listeners for the event are removed.
   * @returns The EventBus instance for chaining.
   */
  off(event: string, callback?: Function): this {
    const listeners = this._events[event];
    if (!listeners) return this;

    if (!callback) {
      delete this._events[event];
      return this;
    }

    for (let i = listeners.length - 1; i >= 0; i--) {
      const listener = listeners[i];
      if (listener.fn !== callback && (listener.fn as any)._fn !== callback) {
        continue;
      }
      listeners.splice(i, 1);
      if (listeners.length === 0) {
        delete this._events[event];
      }
    }
    return this;
  }

  /**
   * Clears all registered events and their listeners.
   * @returns The EventBus instance for chaining.
   */
  clear(): this {
    this._events = {};
    return this;
  }
}

