export function jaroWinkler(s1: string, s2: string): number {
    if (s1 === s2) return 1;
    const n = s1.length;
    const m = s2.length;
    if (n === 0 || m === 0) return 0;

    const window = Math.floor(Math.max(n, m) / 2) - 1;
    const s1Matches = new Array(n).fill(false);
    const s2Matches = new Array(m).fill(false);

    let matches = 0;

    for (let i = 0; i < n; i++) {
        const start = Math.max(0, i - window);
        const end = Math.min(i + window + 1, m);
        for (let j = start; j < end; j++) {
            if (s2[j] === s1[i] && !s2Matches[j]) {
                s1Matches[i] = true;
                s2Matches[j] = true;
                matches++;
                break;
            }
        }
    }

    if (matches === 0) return 0;

    let k = 0;
    let t = 0;
    for (let i = 0; i < n; i++) {
        if (!s1Matches[i]) continue;
        while (!s2Matches[k]) k++;
        if (s1[i] !== s2[k]) {
            t++;
        }
        k++;
    }
    t /= 2;

    const jaro = matches / n + matches / m + (matches - t) / matches;
    let similarity = jaro / 3;

    const prefixLen = Math.min(4, Math.min(n, m));
    let l = 0;
    for (let i = 0; i < prefixLen; i++) {
        if (s1[i] === s2[i]) {
            l++;
        } else {
            break;
        }
    }

    return similarity + l * 0.1 * (1 - similarity);
}

