export type WrapOptions = {
	width?: number;
	lineBreak?: string;
	mode?: 'soft' | 'hard';
	hangingIndent?: string;
	collapseWhitespace?: boolean;
};

function wrapText(text: string, width: number, mode: 'soft' | 'hard'): string[] {
	if (width <= 0) return [text];

	const words = text.split(/\s+/).filter(w => w.length > 0);
	if (words.length === 0) return [''];

	const lines: string[] = [];
	let currentLine = '';

	for (const word of words) {
		if (mode === 'hard' && word.length > width) {
			if (currentLine) {
				lines.push(currentLine);
				currentLine = '';
			}
			let remaining = word;
			while (remaining.length > 0) {
				const chunk = remaining.slice(0, width);
				remaining = remaining.slice(width);
				if (currentLine) {
					lines.push(currentLine);
					currentLine = '';
				}
				currentLine = chunk;
			}
		} else {
			const spacePrefix = currentLine ? ' ' : '';
			const candidate = currentLine + spacePrefix + word;
			if (candidate.length <= width) {
				currentLine = candidate;
			} else {
				if (currentLine) lines.push(currentLine);
				currentLine = word;
			}
		}
	}

	if (currentLine) lines.push(currentLine);
	return lines;
}

export function wordWrap(text: string, options?: WrapOptions): string {
	const {
		width = 80,
		lineBreak = '\n',
		mode = 'soft',
		hangingIndent = '',
		collapseWhitespace = false,
	} = options || {};

	if (text.length === 0) return '';

	const normalizedText = text.replace(/\r\n/g, '\n').replace(/\r/g, '\n');
	const segments = normalizedText.split('\n');

	let allLines: string[] = [];

	for (const segment of segments) {
		let processedSegment = segment;
		if (collapseWhitespace) {
			processedSegment = segment.replace(/[ \t]+/g, ' ').trim();
		}

		const wrappedLines = wrapText(processedSegment, width, mode);
		allLines.push(...wrappedLines);
	}

	if (hangingIndent) {
		for (let i = 1; i < allLines.length; i++) {
			allLines[i] = hangingIndent + allLines[i];
		}
	}

	return allLines.join(lineBreak);
}

