	assert.strictEqual(implementation('one two three', {width: 7, lineBreak: '<br>'}), 'one two<br>three');
	assert.strictEqual(implementation('anti-disestablishmentarianism', {width: 10}), 'anti-\ndisestablishmentarianism');
};

const loadExportedFunction = async (modulePath: string, entry: string): Promise<(...args: readonly unknown[]) => unknown> => {
