type SchemaLike = {
	parse: (input: unknown) => unknown;
	optional: () => SchemaLike;
	nullable: () => SchemaLike;
};

const isSchemaLike = (value: unknown): value is SchemaLike => {
	if (typeof value !== 'object' || value === null) {
		return false;
	}

	const candidate = value as Record<string, unknown>;
